#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
const int N=2022,INF=0x3f3f3f3f;
int x[N],y[N],n;char s[N];vector<int> ans;bool vis[N];
inline bool cha(int x1,int y1,int x2,int y2)
{
//	printf("cha (%d,%d) , (%d,%d) :: %d\n",x1,y1,x2,y2,1ll*x1*y2-1ll*x2*y1>0);
	return 1ll*x1*y2-1ll*x2*y1>0;
}
int main()
{
	scanf("%d",&n);rep(1,n,i)scanf("%d%d",&x[i],&y[i]);
	scanf("%s",s+2);int cur=-1,mn=INF;
	rep(1,n,i)if(x[i]<mn)mn=x[i],cur=i;
	vis[cur]=true;ans.push_back(cur);
	rep(2,n-1,i)
	{
		if(s[i]=='L')
		{
			int idx=0;rep(1,n,j)if(!vis[j])
			{
				if(!idx||cha(x[j]-x[cur],y[j]-y[cur],x[idx]-x[cur],y[idx]-y[cur]))idx=j;
			}
			ans.push_back(cur=idx);vis[cur]=true;
		}
		else
		{
			int idx=0;rep(1,n,j)if(!vis[j])
			{
				if(!idx||!cha(x[j]-x[cur],y[j]-y[cur],x[idx]-x[cur],y[idx]-y[cur]))idx=j;
			}
			ans.push_back(cur=idx);vis[cur]=true;
		}
	}
	rep(1,n,i)if(!vis[i])ans.push_back(i);
	for(int v:ans)printf("%d ",v);puts("");
}
